"""Bedrock AgentCore Memory conversion utilities."""

import json
import logging
from typing import Any, Tuple

from strands.types.session import SessionMessage

logger = logging.getLogger(__name__)

CONVERSATIONAL_MAX_SIZE = 9000


class AgentCoreMemoryConverter:
    """Handles conversion between Strands and Bedrock AgentCore Memory formats."""

    @staticmethod
    def _filter_empty_text(message: dict) -> dict:
        """The Bedrock Converse API can't take empty text as input. So we need to filter out empty text."""
        content = message.get("content", [])
        filtered_content = [item for item in content if "text" not in item or item.get("text", "").strip() != ""]
        return {**message, "content": filtered_content}

    @staticmethod
    def message_to_payload(session_message: SessionMessage) -> list[Tuple[str, str]]:
        """Convert a SessionMessage to Bedrock AgentCore Memory message format.

        Args:
            session_message (SessionMessage): The session message to convert.

        Returns:
            list[Tuple[str, str]]: list of (text, role) tuples for Bedrock AgentCore Memory.
                Returns empty list if message has no content after filtering.
        """
        # First convert to dict (which encodes bytes to base64),
        # then filter empty text on the encoded version
        session_dict = session_message.to_dict()
        filtered_message = AgentCoreMemoryConverter._filter_empty_text(session_dict["message"])
        if not filtered_message.get("content"):
            logger.debug("Skipping message with no content after filtering empty text")
            return []
        session_dict["message"] = filtered_message
        return [(json.dumps(session_dict), filtered_message["role"])]

    @staticmethod
    def events_to_messages(events: list[dict[str, Any]]) -> list[SessionMessage]:
        """Convert Bedrock AgentCore Memory events to SessionMessages.

        Args:
            events (list[dict[str, Any]]): list of events from Bedrock AgentCore Memory.
                Each individual event looks as follows:
                ```
                {
                    "memoryId": "unique_mem_id",
                    "actorId": "actor_id",
                    "sessionId": "session_id",
                    "eventId": "0000001756147154000#ffa53e54",
                    "eventTimestamp": datetime.datetime(2025, 8, 25, 15, 12, 34, tzinfo=tzlocal()),
                    "payload": [
                        {
                            "conversational": {
                                "content": {"text": "What is the weather?"},
                                "role": "USER",
                            }
                        }
                    ],
                    "branch": {"name": "main"},
                }
                ```

        Returns:
            list[SessionMessage]: list of SessionMessage objects.
        """
        messages = []
        for event in reversed(events):
            for payload_item in event.get("payload", []):
                if "conversational" in payload_item:
                    conv = payload_item["conversational"]
                    session_msg = SessionMessage.from_dict(json.loads(conv["content"]["text"]))
                    session_msg.message = AgentCoreMemoryConverter._filter_empty_text(session_msg.message)
                    if session_msg.message.get("content"):
                        messages.append(session_msg)
                elif "blob" in payload_item:
                    try:
                        blob_data = json.loads(payload_item["blob"])
                        if isinstance(blob_data, (tuple, list)) and len(blob_data) == 2:
                            try:
                                session_msg = SessionMessage.from_dict(json.loads(blob_data[0]))
                                session_msg.message = AgentCoreMemoryConverter._filter_empty_text(session_msg.message)
                                if session_msg.message.get("content"):
                                    messages.append(session_msg)
                            except (json.JSONDecodeError, ValueError):
                                logger.error("This is not a SessionMessage but just a blob message. Ignoring")
                    except (json.JSONDecodeError, ValueError):
                        logger.error("Failed to parse blob content: %s", payload_item)
        return messages

    @staticmethod
    def total_length(message: tuple[str, str]) -> int:
        """Calculate total length of a message tuple."""
        return sum(len(text) for text in message)

    @staticmethod
    def exceeds_conversational_limit(message: tuple[str, str]) -> bool:
        """Check if message exceeds conversational size limit."""
        return AgentCoreMemoryConverter.total_length(message) >= CONVERSATIONAL_MAX_SIZE

"""Dictionary wrapper module for bedrock-agentcore memory models."""

from typing import Any, Dict


class DictWrapper:
    """A wrapper class that provides dictionary-like access to data."""

    def __init__(self, data: Dict[str, Any]):
        """Initialize the DictWrapper with data.

        Args:
            data: Dictionary data to wrap
        """
        self._data = data

    def __getattr__(self, name: str) -> Any:
        """Provides direct access to data fields as attributes."""
        return self._data.get(name)

    def __getitem__(self, key: str) -> Any:
        """Provides dictionary-style access to data fields."""
        return self._data[key]

    def get(self, key: str, default: Any = None) -> Any:
        """Provides dict.get() style access to data fields."""
        return self._data.get(key, default)

    def __contains__(self, key: str) -> bool:
        """Support 'in' operator for checking if key exists."""
        return key in self._data

    def keys(self):
        """Return keys from the underlying dictionary."""
        return self._data.keys()

    def values(self):
        """Return values from the underlying dictionary."""
        return self._data.values()

    def items(self):
        """Return items from the underlying dictionary."""
        return self._data.items()

    def __dir__(self):
        """Enable tab completion and introspection of available attributes."""
        return list(self._data.keys()) + ["get"]

    def __repr__(self):
        """Return a JSON-formatted string representation of the data."""
        return self._data.__repr__()

    def __str__(self):
        """Return a JSON-formatted string representation of the data."""
        return self.__repr__()

"""Request context models for Bedrock AgentCore Server.

Contains metadata extracted from HTTP requests that handlers can optionally access.
"""

from contextvars import ContextVar
from typing import Any, Dict, Optional

from pydantic import BaseModel, Field


class RequestContext(BaseModel):
    """Request context containing metadata from HTTP requests."""

    session_id: Optional[str] = Field(None)
    request_headers: Optional[Dict[str, str]] = Field(None)
    request: Optional[Any] = Field(None, description="The underlying Starlette request object")

    class Config:
        """Allow non-serializable types like Starlette Request."""

        arbitrary_types_allowed = True


class BedrockAgentCoreContext:
    """Unified context manager for Bedrock AgentCore."""

    _workload_access_token: ContextVar[Optional[str]] = ContextVar("workload_access_token")
    _oauth2_callback_url: ContextVar[Optional[str]] = ContextVar("oauth2_callback_url")
    _request_id: ContextVar[Optional[str]] = ContextVar("request_id")
    _session_id: ContextVar[Optional[str]] = ContextVar("session_id")
    _request_headers: ContextVar[Optional[Dict[str, str]]] = ContextVar("request_headers")

    @classmethod
    def set_workload_access_token(cls, token: str):
        """Set the workload access token in the context."""
        cls._workload_access_token.set(token)

    @classmethod
    def get_workload_access_token(cls) -> Optional[str]:
        """Get the workload access token from the context."""
        try:
            return cls._workload_access_token.get()
        except LookupError:
            return None

    @classmethod
    def set_oauth2_callback_url(cls, workload_callback_url: str):
        """Set the oauth2 callback url in the context."""
        cls._oauth2_callback_url.set(workload_callback_url)

    @classmethod
    def get_oauth2_callback_url(cls) -> Optional[str]:
        """Get the oauth2 callback url from the context."""
        try:
            return cls._oauth2_callback_url.get()
        except LookupError:
            return None

    @classmethod
    def set_request_context(cls, request_id: str, session_id: Optional[str] = None):
        """Set request-scoped identifiers."""
        cls._request_id.set(request_id)
        cls._session_id.set(session_id)

    @classmethod
    def get_request_id(cls) -> Optional[str]:
        """Get current request ID."""
        try:
            return cls._request_id.get()
        except LookupError:
            return None

    @classmethod
    def get_session_id(cls) -> Optional[str]:
        """Get current session ID."""
        try:
            return cls._session_id.get()
        except LookupError:
            return None

    @classmethod
    def set_request_headers(cls, headers: Dict[str, str]):
        """Set request headers in the context."""
        cls._request_headers.set(headers)

    @classmethod
    def get_request_headers(cls) -> Optional[Dict[str, str]]:
        """Get request headers from the context."""
        try:
            return cls._request_headers.get()
        except LookupError:
            return None

"""Bedrock AgentCore runtime utilities for object conversion and serialization."""

from dataclasses import asdict, is_dataclass
from typing import Any


def convert_complex_objects(obj: Any, _depth: int = 0) -> Any:
    """Recursively convert complex objects to serializable dictionaries."""
    # Prevent infinite recursion
    if _depth > 50:
        return f"<too_deep:{type(obj).__name__}>"

    # Handle Pydantic models (like AIMessage)
    if hasattr(obj, "model_dump"):
        return obj.model_dump()

    # Handle dataclasses (like AgentResult)
    elif is_dataclass(obj):
        return asdict(obj)

    # Handle dictionaries recursively
    elif isinstance(obj, dict):
        return {k: convert_complex_objects(v, _depth + 1) for k, v in obj.items()}

    # Handle lists and tuples recursively
    elif isinstance(obj, (list, tuple)):
        return [convert_complex_objects(item, _depth + 1) for item in obj]

    # Handle sets (convert to list)
    elif isinstance(obj, set):
        return [convert_complex_objects(item, _depth + 1) for item in obj]

    # Return primitives as-is
    else:
        return obj

"""Configuration helpers for Bedrock AgentCore Tools.

This module provides dataclasses and helper functions to simplify working with
browser and code interpreter configurations.
"""

from dataclasses import dataclass, field
from typing import Dict, List, Optional


@dataclass
class VpcConfig:
    """VPC configuration for browsers and code interpreters.

    Attributes:
        security_groups: List of security group IDs
        subnets: List of subnet IDs
    """

    security_groups: List[str]
    subnets: List[str]

    def to_dict(self) -> Dict:
        """Convert to API-compatible dictionary."""
        return {"securityGroups": self.security_groups, "subnets": self.subnets}


@dataclass
class NetworkConfiguration:
    """Network configuration for browsers and code interpreters.

    Attributes:
        network_mode: Either "PUBLIC" or "VPC"
        vpc_config: VPC configuration (required if network_mode is VPC)
    """

    network_mode: str = "PUBLIC"
    vpc_config: Optional[VpcConfig] = None

    def __post_init__(self):
        """Validate configuration."""
        if self.network_mode not in ["PUBLIC", "VPC"]:
            raise ValueError(f"network_mode must be 'PUBLIC' or 'VPC', got '{self.network_mode}'")

        if self.network_mode == "VPC" and not self.vpc_config:
            raise ValueError("vpc_config is required when network_mode is 'VPC'")

    def to_dict(self) -> Dict:
        """Convert to API-compatible dictionary."""
        config = {"networkMode": self.network_mode}
        if self.vpc_config:
            config["vpcConfig"] = self.vpc_config.to_dict()
        return config

    @classmethod
    def public(cls) -> "NetworkConfiguration":
        """Create a PUBLIC network configuration."""
        return cls(network_mode="PUBLIC")

    @classmethod
    def vpc(cls, security_groups: List[str], subnets: List[str]) -> "NetworkConfiguration":
        """Create a VPC network configuration.

        Args:
            security_groups: List of security group IDs
            subnets: List of subnet IDs

        Returns:
            NetworkConfiguration with VPC settings
        """
        return cls(network_mode="VPC", vpc_config=VpcConfig(security_groups, subnets))


